use std::sync::{Arc, Mutex};
use std::thread;

struct Inventory {
    stock_levels: Vec<i32>,
}

impl Inventory {
    fn new(stock_levels: Vec<i32>) -> Self {
        Inventory { stock_levels }
    }

    fn check_stock(&self, product_id: i32) -> Option<i32> {
        self.stock_levels.get(product_id as usize).cloned()
    }

    fn update_stock(&self, product_id: i32, quantity: i32) -> bool {
        let mut lock = self.lock().unwrap();
        if let Some(stock_level) = lock[product_id as usize] {
            if stock_level >= quantity {
                lock[product_id as usize] -= quantity;
                true
            } else {
                false
            }
        } else {
            false
        }
    }

    fn lock(&self) -> Result<&mut Vec<i32>, std::sync::PoisonError<i32>> {
        self.stock_levels.lock()
    }
}

fn main() {
    let stock_levels = vec![100, 200, 300];
    let inventory = Arc::new(Mutex::new(Inventory::new(stock_levels)));

    let mut handles = vec![];

    for i in 0..10 {
        let inventory_clone = Arc::clone(&inventory);
        let handle = thread::spawn(move || {
            let product_id = i % 3;
            if let Some(stock_level) = inventory_clone.lock().unwrap()[product_id as usize] {
                println!("Checking stock level for product {}: {}", product_id, stock_level);
                if inventory_clone.update_stock(product_id, 10) {
                    println!("Updated stock level for product {} to {}", product_id, inventory_clone.lock().unwrap()[product_id as usize]);
                } else {
                    println!("Insufficient stock for product {}", product_id);
                }
            }
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }
}